test("Hey mom, sorry I couldn't make it to your birthday...");
console.log("========================");
if (isFunctionType(isSpamMessage)) {
  console.log("isSpamMessage is a classic function");
} else {
  console.log("isSpamMessage is a fat arrow function");
}

